body.script:
promise_test(async () => {
  const t1 = document.getElementById('t1');
  assert_color(t1, 'rgb(0, 0, 0)', 'Initially black');

  await new test_driver.Actions().pointerMove(0, 0, {origin: t1}).send();
  assert_color(t1, LIME, 'Green on hover');

  // Move away to reset state for next test
  await new test_driver.Actions().pointerMove(0, 0).send();
}, 'Negated :hover on span');

promise_test(async () => {
  const t2 = document.getElementById('t2');
  assert_color(t2, 'rgb(0, 0, 0)', 'Initially black');

  await new test_driver.Actions().pointerMove(0, 0, {origin: t2}).send();
  assert_color(t2, LIME, 'Green on hover');
}, 'Negated :hover on link');
